        align-items: center;
        gap: 10px;
      }
      h2 {
        margin: 0;
        color: #fde68a;
        font: 800 15px/1 ui-sans-serif, system-ui, sans-serif;
        letter-spacing: 0;
      }
      .sub {
        margin-top: 3px;
        color: #cbd5e1;
        font-size: 9px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      }
      button {
        height: 30px;
        padding: 0 10px;
        border: 1px solid rgba(251, 191, 36, 0.45);
        border-radius: 6px;
        background: rgba(15, 23, 42, 0.76);
        color: #fde68a;
        font: inherit;
        cursor: pointer;
      }
      button.active {
        background: rgba(180, 83, 9, 0.38);
        color: #fff7ed;
      }
      .stage {
        position: relative;
