        transform: scaleX(var(--scale, 0.2));
        background: linear-gradient(90deg, rgba(251, 191, 36, 0.48), rgba(248, 250, 252, 0));
      }
      .readout {
        position: absolute;
        right: 10px;
        bottom: 8px;
        color: #fed7aa;
      }
      .controls {
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 10px;
      }
      label {
        display: grid;
        gap: 5px;
        color: #fed7aa;
      }
      .row {
        display: flex;
        justify-content: space-between;
        gap: 8px;
      }
