/**
 * Simulation Controller — Time & Phase Management
 *
 * Manages the geological time scale for island birth simulation.
 * Phases: ocean floor → eruption → barren island → colonization → mature ecosystem
 */

// Phase definitions (year thresholds)
const PHASES = [
  { name: "海底火山",     nameEn: "Submarine Volcano", endYear: 500_000 },
  { name: "噴火",         nameEn: "Eruption",          endYear: 2_000_000 },
  { name: "裸の島",       nameEn: "Barren Island",     endYear: 5_000_000 },
  { name: "生態系形成",   nameEn: "Colonization",      endYear: Infinity },
];

// Years advanced per frame in each phase
const YEARS_PER_FRAME = [
  5_000,    // Phase 0: ocean floor (fast — not much to see)
  8_000,    // Phase 1: eruption (moderate — watch island rise)
  15_000,   // Phase 2: barren island (fast — waiting period)
  25_000,   // Phase 3: colonization (watch birds & trees grow slowly)
];

export class Simulation {
  constructor() {
    this.year = 0;
    this.phase = 0;
    this.paused = false;
    this.speedMultiplier = 1; // 1x, 2x, 4x, 8x
  }

  update() {
    if (this.paused) return;

    const base = YEARS_PER_FRAME[this.phase] || YEARS_PER_FRAME[YEARS_PER_FRAME.length - 1];
    this.year += base * this.speedMultiplier;

    // Advance phase if threshold reached
    while (this.phase < PHASES.length - 1 && this.year >= PHASES[this.phase].endYear) {
      this.phase++;
    }
  }

  /** Year within the current phase as 0..1 progress */
  getProgress() {
    const start = this.phase > 0 ? PHASES[this.phase - 1].endYear : 0;
    const end = PHASES[this.phase].endYear;
    if (end === Infinity) return 1;
    return Math.min(1, (this.year - start) / (end - start));
  }

  getYear() {
    return this.year;
  }

  getPhase() {
    return this.phase;
  }

  getPhaseName() {
    return PHASES[this.phase]?.name ?? "";
  }

  getPhaseNameEn() {
    return PHASES[this.phase]?.nameEn ?? "";
  }

  /** Format year for display: "Year 1,234,567" */
  getFormattedYear() {
    return `Year ${Math.floor(this.year).toLocaleString()}`;
  }

  speedUp() {
    this.speedMultiplier = Math.min(16, this.speedMultiplier * 2);
  }

  speedDown() {
    this.speedMultiplier = Math.max(0.25, this.speedMultiplier / 2);
  }

  getSpeedLabel() {
    return `${this.speedMultiplier}x`;
  }
}

